  CLASSIC = 'CLASSIC',
  FAMILY = 'FAMILY',
  PHOTO = 'PHOTO'
}

export interface ItineraryItem {
  time: string;
  location: string;
  description: string;
  highlight?: string;
  note?: string; // e.g. ticket price
  iconType?: 'walk' | 'car' | 'food' | 'photo' | 'landmark';
}

export interface LunchOption {
  name: string;
  type: string;
  priceLevel: string;
}

