import React from 'react';
import { X, MapPin, Navigation, Camera, Utensils, Footprints, Car } from 'lucide-react';
import { TourPackage, ItineraryItem } from '../types';

interface ItineraryDetailProps {
  pkg: TourPackage;
  onClose: () => void;
  onContact: () => void;
}

const getIcon = (type?: string) => {
  switch (type) {
    case 'walk': return <Footprints size={16} />;
    case 'car': return <Car size={16} />;
    case 'food': return <Utensils size={16} />;
    case 'photo': return <Camera size={16} />;
    case 'landmark': return <MapPin size={16} />;
    default: return <Navigation size={16} />;
  }
};

const ItineraryDetail: React.FC<ItineraryDetailProps> = ({ pkg, onClose, onContact }) => {
  return (
    <div className="fixed inset-0 z-50 bg-white flex flex-col animate-in slide-in-from-bottom-10 duration-300">
      {/* Header */}
      <div className="relative h-48 shrink-0">
        <img src={pkg.coverImage} className="w-full h-full object-cover brightness-75" alt="cover" />
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 bg-black/30 backdrop-blur-md p-2 rounded-full text-white z-10"
        >
          <X size={20} />
        </button>
        <div className="absolute bottom-4 left-4 right-4">
          <h2 className="text-2xl font-bold text-white mb-1 shadow-black/50 drop-shadow-md">{pkg.title}</h2>
        </div>
      </div>

      {/* Content Scroll Area */}
      <div className="flex-1 overflow-y-auto bg-stone-50 pb-24">
        {/* Intro */}
        <div className="bg-white p-6 mb-2">
          <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 mb-4">
            <h4 className="font-bold text-orange-800 text-sm mb-1">💡 适合人群</h4>
            <p className="text-xs text-orange-700/80 leading-relaxed">{pkg.idealFor}</p>
          </div>
          <p className="text-sm text-slate-600 leading-relaxed">{pkg.description}</p>
        </div>

        {/* Timeline */}
        <div className="p-6">
          <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
            <span className="w-1 h-5 bg-stone-900 rounded-full"></span>
            行程安排 (可微调)
          </h3>

          <div className="relative border-l-2 border-stone-200 ml-3 space-y-8">
            {pkg.itinerary.map((item, idx) => (
              <div key={idx} className="relative pl-8">
                {/* Timeline Dot */}
                <div className="absolute -left-[9px] top-0 bg-stone-50 p-1">
                  <div className={`w-3 h-3 rounded-full ${idx === 0 ? 'bg-orange-500' : 'bg-stone-300'}`}></div>
                </div>

                {/* Time */}
                <span className="inline-block text-xs font-mono font-semibold text-stone-400 mb-1 bg-stone-100 px-2 py-0.5 rounded">
